#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;unsigned seed=998244353;typedef long long ll;
inline unsigned Rnd(){seed^=seed<<17;seed^=seed>>13;seed^=seed<<7;return seed;}
//bool f1;
struct LIST{int l,val;}a[N];int cnt,st[N],ed[N],ix[N];ll sz[N];//编号i的链开头/结尾/大小, j号序列所用的链的编号 
struct Seg{int l,r;ll sm;}t[N*25];int cst,rt[N];int n,q,c;
//bool f2;
inline void update(int x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm;}
inline int merge(int x,int y,int l=0,int r=n+q)//线段树合并 
{
	if(!x||!y)return x|y;if(l==r){t[x].sm+=t[y].sm;return x;}int mid=(l+r)>>1;
	t[x].l=merge(t[x].l,t[y].l,l,mid);t[x].r=merge(t[x].r,t[y].r,mid+1,r);update(x);return x;
}
inline void add(int &x,int p,int w,int l=0,int r=n+q)
{
	if(!x)x=++cst;if(l==r){t[x].sm+=w;return;} int mid=(l+r)>>1;
	p<=mid?add(t[x].l,p,w,l,mid):add(t[x].r,p,w,mid+1,r); update(x);
}
inline int qry(int x,int p,int l=0,int r=n+q)
{
	if(!x)return 0;if(l==r)return t[x].sm;int mid=(l+r)>>1;
	return p<=mid?qry(t[x].l,p,l,mid):qry(t[x].r,p,mid+1,r);
}
inline int kth(int x,int k,int l=0,int r=n+q)
{
	if(l==r)return l;int mid=(l+r)>>1,lsz=t[t[x].l].sm;
	return lsz>=k?kth(t[x].l,k,l,mid):kth(t[x].r,k-lsz,mid+1,r);
}
inline int Merge(int x,int y)
{
	if(!sz[x])return y;if(!sz[y])return x;
	sz[x]+=sz[y];a[st[y]].l=ed[x];ed[x]=ed[y];return x;
}//链表合并 
inline void Add(int x,int w){a[++cnt].val=w;a[cnt].l=ed[x];ed[x]=cnt;if(!sz[x])st[x]=cnt;++sz[x];}
inline void Del(int x){int u=ed[x];ed[x]=a[u].l;a[u].l=0;--sz[x];if(!sz[x])st[x]=0;} 

inline void op1(){int x=read(),y=read();Add(ix[x],y);add(rt[x],y,1);}
inline void op2(){int x=read();if(sz[ix[x]])add(rt[x],a[ed[ix[x]]].val,-1),Del(ix[x]);}
ll tsm[N];int p[N];
inline void op3()
{
	int m=read();
	rep(1,m,i)tsm[i]=t[rt[p[i]=read()]].sm;
	rep(2,m,i)tsm[i]+=tsm[i-1];
	ll siz=tsm[m],T=log2(siz)+10;
	while(T--)
	{
		ll x=Rnd()%siz+1;
		ll k=lower_bound(tsm+1,tsm+m+1,x)-tsm;
		int u=kth(rt[p[k]],x-tsm[k-1]);
		ll s=0;rep(1,m,i)s+=qry(rt[p[i]],u);
		if(2*s>siz){printf("%d\n",u);return;}
	}
	puts("-1");return;
}
inline void op4()
{
	int x=read(),y=read(),z=read();;
	ix[z]=Merge(ix[x],ix[y]);ix[x]=ix[y]=0;
	rt[z]=merge(rt[x],rt[y]);rt[x]=rt[y]=0;
}
int main()
{
	n=c=read();q=read();rep(1,n,i)
	{
		ix[i]=i;int T=read();
		while(T--){int x=read();Add(ix[i],x);add(rt[i],x,1);}
	}
	rep(1,q,tt)
	{
		switch(read())
		{
			case 1: op1();break;
			case 2: op2();break;
			case 3: op3();break;
			case 4: op4();break;
		}
	}
}
